import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const ProfilePage = () => {
  const { user, setUser } = useAuth();

  const [name, setName] = useState(user?.name || '');
  const [username, setUsername] = useState(user?.username || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [pic, setPic] = useState(null);
  const [curPw, setCurPw] = useState('');
  const [newPw, setNewPw] = useState('');
  const [msg, setMsg] = useState('');
  const [msgType, setMsgType] = useState(''); // ✅ NEW (success/error)
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem("user-theme");
    setDarkMode(saved === "dark");
  }, []);

  useEffect(() => {
    const handleThemeChange = () => {
      const saved = localStorage.getItem("user-theme");
      setDarkMode(saved === "dark");
    };
    window.addEventListener("storage", handleThemeChange);
    return () => window.removeEventListener("storage", handleThemeChange);
  }, []);

  useEffect(() => {
    if (!msg) return;
    const timer = setTimeout(() => {
      setMsg('');
      setMsgType('');
    }, 3000);
    return () => clearTimeout(timer);
  }, [msg]);

  const handleProfile = async (e) => {
    e.preventDefault();
    setMsg('');

    const fd = new FormData();
    fd.append('name', name);
    fd.append('bio', bio);
    fd.append('username', username);
    if (pic) fd.append('profilePic', pic);

    try {
      const { data } = await API.put('/auth/profile', fd);
      setUser(data);
      setMsgType('success');
      setMsg('Profile updated successfully!');
    } catch (err) {
      setMsgType('error');
      setMsg(err.response?.data?.message || 'Error updating profile');
    }
  };

  const handlePassword = async (e) => {
    e.preventDefault();
    setMsg('');

    try {
      await API.put('/auth/change-password', {
        currentPassword: curPw,
        newPassword: newPw,
      });

      setMsgType('success');
      setMsg('Password changed successfully!');
      setCurPw('');
      setNewPw('');
    } catch (err) {
      setMsgType('error');
      setMsg(err.response?.data?.message || 'Error changing password');
    }
  };

  const picSrc = user?.profilePic
    ? `http://localhost:5000/uploads/${user.profilePic}`
    : '/default-avatar.png';

  const styles = {
    page: {
      background: darkMode ? "#560032" : "#FAE8ED",
      minHeight: '100vh',
      padding: '40px 20px',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'flex-start',
    },

    container: {
      width: '100%',
      maxWidth: '700px',
      backgroundColor: darkMode ? "#2e091e" : "#f7c6d9",
      padding: '30px',
      borderRadius: '20px',
      boxShadow: "0 10px 30px rgba(0,0,0,0.15)",
    },

    header: {
      textAlign: "center",
      marginBottom: "25px",
    },

    profilePic: {
      width: '120px',
      height: '120px',
      borderRadius: '50%',
      objectFit: 'cover',
      marginBottom: '10px',
      border: "3px solid white",
    },

    username: {
      fontWeight: "bold",
      fontSize: "18px",
    },

    bio: {
      fontSize: "14px",
      opacity: 0.8,
    },

    message: {
      textAlign: "center",
      marginBottom: "15px",
      padding: "10px",
      borderRadius: "8px",
      fontWeight: "bold",
      backgroundColor:
        msgType === "success"
          ? "#d1fae5"
          : msgType === "error"
          ? "#fee2e2"
          : "transparent",
      color:
        msgType === "success"
          ? "#065f46"
          : msgType === "error"
          ? "#991b1b"
          : "#000",
    },

    section: {
      background: darkMode ? "#381727" : "#fff",
      padding: "20px",
      borderRadius: "15px",
      marginBottom: "20px",
      boxShadow: "0 4px 10px rgba(0,0,0,0.08)",
    },

    title: {
      fontWeight: "bold",
      marginBottom: "15px",
      fontSize: "18px",
    },

    formGroup: {
      display: "flex",
      flexDirection: "column",
      marginBottom: "12px",
    },

    label: {
      fontSize: "12px",
      marginBottom: "5px",
      fontWeight: "bold",
    },

    input: {
      padding: "12px",
      borderRadius: "10px",
      border: "1px solid #ccc",
      outline: "none",
      transition: "0.2s",
    },

    textarea: {
      padding: "12px",
      borderRadius: "10px",
      border: "1px solid #ccc",
      resize: "none",
    },

    fileRow: {
      display: "flex",
      alignItems: "center",
      gap: "10px",
      marginTop: "10px",
    },

    button: {
      marginTop: "15px",
      padding: "12px",
      borderRadius: "10px",
      border: "none",
      cursor: "pointer",
      fontWeight: "bold",
      backgroundColor: darkMode ? "#c46392" : "#0c4b34",
      color: "#fff",
      transition: "0.2s",
    },
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>

        <div style={styles.header}>
          <img src={picSrc} alt="Profile" style={styles.profilePic} />
          <div style={styles.username}>@{user?.username}</div>
          <div style={styles.bio}>{user?.bio || "No bio yet."}</div>
        </div>

        {msg && <div style={styles.message}>{msg}</div>}

        <form style={styles.section} onSubmit={handleProfile}>
          <div style={styles.title}>Edit Profile</div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Display Name</label>
            <input value={name} onChange={(e) => setName(e.target.value)} style={styles.input} />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Email</label>
            <input value={user?.email || ""} disabled style={styles.input} />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Username</label>
            <input value={username} onChange={(e) => setUsername(e.target.value)} style={styles.input} />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Bio</label>
            <textarea value={bio} onChange={(e) => setBio(e.target.value)} rows={3} style={styles.textarea} />
          </div>

          <div style={styles.fileRow}>
            <input type="file" onChange={(e) => setPic(e.target.files[0])} />
            <span>{pic ? pic.name : "No file chosen"}</span>
          </div>

          <button type="submit" style={styles.button}>Save Profile</button>
        </form>

        <form style={styles.section} onSubmit={handlePassword}>
          <div style={styles.title}>Change Password</div>

          <input type="password" placeholder="Current password" value={curPw} onChange={(e) => setCurPw(e.target.value)} style={styles.input} />
          <input type="password" placeholder="New password" value={newPw} onChange={(e) => setNewPw(e.target.value)} style={styles.input} />

          <button type="submit" style={styles.button}>Change Password</button>
        </form>

      </div>
    </div>
  );
};

export default ProfilePage;
